		if (plan == path) {
			return true;
		}
		if (plan instanceof JoinPlan) {
			JoinPlan join = (JoinPlan) plan;
			return appliesTo(join.left) || appliesTo(join.right);
		}
		return plan instanceof FilterPlan && appliesTo(((FilterPlan) plan).arg);
